qss:
QWidget { background: #170606; color: #ffe8d5; font-family: Segoe UI, Arial, sans-serif; font-size: 10pt; }
QMainWindow, QDialog { background: #170606; }
QGroupBox { background: #260b08; border: 1px solid #8c2a17; border-radius: 8px; margin-top: 12px; padding: 10px; font-weight: bold; }
QGroupBox::title { subcontrol-origin: margin; left: 12px; padding: 0 4px; color: #ff4b22; }
QTabWidget::pane { border: 1px solid #8c2a17; background: #260b08; }
QTabBar::tab { background: #120303; color: #ffe8d5; padding: 8px 14px; border: 1px solid #8c2a17; border-bottom: none; min-width: 100px; }
QTabBar::tab:selected { background: #b42112; color: #fff0df; font-weight: bold; }
QTabBar::tab:hover { background: #53170f; color: #fff0df; }
QPushButton { background: #53170f; color: #fff0df; border: 1px solid #ff4b22; border-radius: 6px; padding: 7px 12px; font-weight: 600; }
QPushButton:hover { background: #ff4b22; color: #fff0df; }
QPushButton:disabled { background: #7a3328; color: #120303; border-color: #8c2a17; }
QLineEdit, QTextEdit, QTextBrowser, QPlainTextEdit, QComboBox, QSpinBox, QDoubleSpinBox { background: #120303; color: #ffe8d5; border: 1px solid #8c2a17; border-radius: 5px; padding: 5px; selection-background-color: #ff4b22; selection-color: #fff0df; }
QComboBox QAbstractItemView { background: #120303; color: #ffe8d5; selection-background-color: #ff4b22; selection-color: #fff0df; border: 1px solid #8c2a17; }
QTableWidget { background: #120303; alternate-background-color: #260b08; color: #ffe8d5; gridline-color: #8c2a17; selection-background-color: #ff4b22; selection-color: #fff0df; }
QHeaderView::section { background: #b42112; color: #fff0df; padding: 6px; border: 1px solid #8c2a17; font-weight: bold; }
QScrollBar:vertical { background: #260b08; width: 14px; }
QScrollBar::handle:vertical { background: #ff4b22; border-radius: 6px; min-height: 24px; }
QScrollBar:horizontal { background: #260b08; height: 14px; }
QScrollBar::handle:horizontal { background: #ff4b22; border-radius: 6px; min-width: 24px; }
QCheckBox { spacing: 6px; }
QLabel { color: #ffe8d5; }
